import java.io.*;
import java.util.*;

public class Main {
    static class Node {
        int val;
        Node left, right;
        Node(int v) { this.val = v; }
    }

    private static void inorderDetect(Node cur, Node[] first, Node[] second, Node[] prev) {
        if (cur == null) return;
        inorderDetect(cur.left, first, second, prev);
        if (prev[0] != null && prev[0].val > cur.val) {
            if (first[0] == null) first[0] = prev[0];
            second[0] = cur;
        }
        prev[0] = cur;
        inorderDetect(cur.right, first, second, prev);
    }

    private static void recoverBST(Node root) {
        Node[] first = new Node[1];
        Node[] second = new Node[1];
        Node[] prev = new Node[1];
        inorderDetect(root, first, second, prev);
        if (first[0] != null && second[0] != null) {
            int tmp = first[0].val;
            first[0].val = second[0].val;
            second[0].val = tmp;
        }
    }

    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        String line;
        line = br.readLine();
        while (line != null && line.trim().isEmpty()) line = br.readLine();
        int T = Integer.parseInt(line.trim());
        StringBuilder sb = new StringBuilder();
        for (int t = 0; t < T; t++) {
            // read N
            line = br.readLine();
            while (line != null && line.trim().isEmpty()) line = br.readLine();
            int N = Integer.parseInt(line.trim());
            if (N == 0) {
                sb.append("OK! BST recovered. Well done!").append('\n');
                continue;
            }
            Map<Integer, Node> map = new HashMap<>();
            Set<Integer> childSet = new HashSet<>();
            // For N == 1 there are no edges, we still need a node.
            if (N == 1) {
                // create a dummy node with any value, e.g., 0
                Node single = new Node(0);
                recoverBST(single);
                sb.append("OK! BST recovered. Well done!").append('\n');
                continue;
            }
            for (int i = 0; i < N - 1; i++) {
                line = br.readLine();
                while (line != null && line.trim().isEmpty()) line = br.readLine();
                StringTokenizer st = new StringTokenizer(line);
                int p = Integer.parseInt(st.nextToken());
                int c = Integer.parseInt(st.nextToken());
                char dir = st.nextToken().charAt(0);
                Node parent = map.computeIfAbsent(p, Node::new);
                Node child = map.computeIfAbsent(c, Node::new);
                if (dir == 'L') parent.left = child; else parent.right = child;
                childSet.add(c);
                // ensure parent also recorded as possible root (if not child)
                if (!childSet.contains(p)) {
                    // nothing to do, just keep map entry
                }
            }
            // find root (value that never appeared as child)
            int rootVal = -1;
            for (int val : map.keySet()) {
                if (!childSet.contains(val)) { rootVal = val; break; }
            }
            // In case the root value is not in map (possible when N==1 handled earlier), fallback to any node.
            Node root = (rootVal != -1) ? map.get(rootVal) : map.values().iterator().next();
            recoverBST(root);
            sb.append("OK! BST recovered. Well done!").append('\n');
        }
        System.out.print(sb.toString());
    }
}

